let totalViolations = 0;
let activeCameras = new Set();
let minuteViolations = 0;
let totalConfidence = 0;
let confidenceCount = 0;

let hourlyChart = null;
let vehicleDist = { motorcycle: 0, car: 0 };
let cameraDist = {};
let activeTrendTab = 'semua';
let trendMaxPoints = 19;
let trendLabels = [];
let trendData = { semua: [], CCTV_BASUKI_RAHMAT: [], CCTV_BAMBU_RUNCING: [], CCTV_BASRA_LOOP: [], CCTV_DARMO_MERCURE: [] };

function initTrendChartData() {
    let now = new Date();
    for (let i = 0; i < trendMaxPoints; i++) {
        let d = new Date(now.getTime() + i * 60000);
        let hh = String(d.getHours()).padStart(2, '0');
        let mm = String(d.getMinutes()).padStart(2, '0');
        trendLabels.push(`${hh}.${mm}`);
        Object.keys(trendData).forEach(k => trendData[k].push(0));
    }
}
initTrendChartData();

function shiftTrendChartIfNeeded() {
    if (trendLabels.length === 0) return;
    let now = new Date();
    let hh = String(now.getHours()).padStart(2, '0');
    let mm = String(now.getMinutes()).padStart(2, '0');
    let currentTimeStr = `${hh}.${mm}`;

    if (!trendLabels.includes(currentTimeStr)) {
        let dNow = new Date();
        dNow.setSeconds(0);
        dNow.setMilliseconds(0);
        
        let lastTimeStr = trendLabels[trendLabels.length - 1];
        let [l_hh, l_mm] = lastTimeStr.split('.');
        let dLast = new Date();
        dLast.setHours(parseInt(l_hh, 10), parseInt(l_mm, 10), 0, 0);
        
        if (dNow < dLast && dLast.getHours() === 23 && dNow.getHours() === 0) {
            dNow.setDate(dNow.getDate() + 1);
        }

        if (dNow > dLast) {
            let diffMins = Math.floor((dNow - dLast) / 60000);
            for (let i = 0; i < diffMins; i++) {
                trendLabels.shift();
                Object.values(trendData).forEach(arr => arr.shift());
                
                dLast.setTime(dLast.getTime() + 60000);
                let n_hh = String(dLast.getHours()).padStart(2, '0');
                let n_mm = String(dLast.getMinutes()).padStart(2, '0');
                trendLabels.push(`${n_hh}.${n_mm}`);
                Object.values(trendData).forEach(arr => arr.push(0));
            }
            if (typeof hourlyChart !== 'undefined' && hourlyChart !== null) {
                hourlyChart.update();
            }
        }
    }
}

// Reset pelanggaran menit ini setiap 1 menit (60000 ms)
setInterval(() => {
    minuteViolations = 0;
    const kpiMinute = document.getElementById("kpi-minute");
    if (kpiMinute) kpiMinute.innerText = minuteViolations;
    shiftTrendChartIfNeeded();
}, 60000);

// Menangkap event stream dari backend Flask secara Real-Time
const eventSource = new EventSource("/stream");

eventSource.onmessage = function (event) {
    if (event.data === "ping") return; // abaikan ping heartbeat

    // Parse JSON dari payload Kafka
    const payload = JSON.parse(event.data);
    console.log("🚨 Event Pelanggaran Baru:", payload);

    // Hilangkan loading state
    document.getElementById("loadingOverlay").style.display = "none";

    // TODO: Sesuaikan dengan id element Anda
    totalViolations++;
    minuteViolations++;
    activeCameras.add(payload.camera_id);
    
    if (typeof payload.confidence_score === "number") {
        totalConfidence += payload.confidence_score;
        confidenceCount++;
        const avgConf = totalConfidence / confidenceCount;
        document.getElementById("kpi-conf").innerText = (avgConf * 100).toFixed(1) + "%";
    }

    document.getElementById("kpi-total").innerText = totalViolations;
    document.getElementById("kpi-cameras").innerText = `${activeCameras.size}/4`;
    document.getElementById("kpi-minute").innerText = minuteViolations;
    
    shiftTrendChartIfNeeded();
    let now = new Date();
    let hh = String(now.getHours()).padStart(2, '0');
    let mm = String(now.getMinutes()).padStart(2, '0');
    let currentTimeStr = `${hh}.${mm}`;
    let idx = trendLabels.indexOf(currentTimeStr);
    if (idx !== -1) {
        trendData['semua'][idx]++;
        if (payload.camera_id && trendData[payload.camera_id]) {
            trendData[payload.camera_id][idx]++;
        }
        if (typeof hourlyChart !== 'undefined' && hourlyChart !== null) {
            hourlyChart.update();
        }
    }

    if (payload.vehicle_type === 'motorcycle') vehicleDist.motorcycle++;
    else if (payload.vehicle_type === 'car') vehicleDist.car++;

    if (charts.vehicle) {
        charts.vehicle.data.datasets[0].data = Object.values(vehicleDist);
        charts.vehicle.update();
    }

    if (payload.camera_id) {
        cameraDist[payload.camera_id] = (cameraDist[payload.camera_id] || 0) + 1;
    }

    if (charts.camera) {
        charts.camera.data.datasets[0].data = CAMERAS.map(c => cameraDist[c.id] || 0);
        charts.camera.update();
    }
};

eventSource.onerror = function (err) {
    console.error("Terputus dari stream real-time", err);
};



