// ============================================================
// SIMULATED DATA ENGINE
// ============================================================
// Since we're standalone (no live Delta Lake connection),
// we generate realistic simulated data seeded from real camera configs.

function seedRand(seed) {
    let s = seed;
    return () => { s = (s * 1664525 + 1013904223) & 0xffffffff; return (s >>> 0) / 0xffffffff; };
}

const rng = seedRand(Date.now());

const VEHICLE_TYPES = ['motorcycle', 'car', 'bus', 'truck'];
const VEHICLE_ICONS = { motorcycle: '🏍️', car: '🚗', bus: '🚌', truck: '🚛' };

// Realistic violation profile per camera (based on Surabaya traffic reality)
const CAMERA_PROFILES = {
    CCTV_BASUKI_RAHMAT: { base: 45, peak_hours: [7, 8, 12, 17, 18], multiplier: 2.8, vehicle_bias: [0.68, 0.24, 0.05, 0.03] },
    CCTV_BAMBU_RUNCING: { base: 32, peak_hours: [7, 8, 13, 17, 18, 19], multiplier: 2.5, vehicle_bias: [0.72, 0.20, 0.04, 0.04] },
    CCTV_BASRA_LOOP: { base: 58, peak_hours: [6, 7, 8, 12, 17, 18], multiplier: 3.1, vehicle_bias: [0.60, 0.30, 0.06, 0.04] },
    CCTV_DARMO_MERCURE: { base: 38, peak_hours: [7, 8, 17, 18, 19, 20], multiplier: 2.3, vehicle_bias: [0.65, 0.25, 0.06, 0.04] },
};

// Pick weighted random vehicle
function pickVehicle(bias) {
    let r = rng(), acc = 0;
    for (let i = 0; i < bias.length; i++) {
        acc += bias[i];
        if (r < acc) return VEHICLE_TYPES[i];
    }
    return VEHICLE_TYPES[0];
}

// Generate hourly data for today (0..current_hour)
function generateHourlyData() {
    const now = new Date();
    const currentHour = now.getHours();
    const hourly = [];

    for (let h = 0; h <= currentHour; h++) {
        let total = 0;
        for (const [cam_id, profile] of Object.entries(CAMERA_PROFILES)) {
            let count = profile.base;
            if (profile.peak_hours.includes(h)) count *= profile.multiplier;
            count = Math.round(count * (0.7 + rng() * 0.6));
            total += count;
        }
        hourly.push({ hour: h, total });
    }
    return hourly;
}

function generateCameraStats() {
    const now = new Date();
    const currentHour = now.getHours();

    return CAMERAS.map(cam => {
        const profile = CAMERA_PROFILES[cam.id];
        let total = 0;
        for (let h = 0; h <= currentHour; h++) {
            let count = profile.base;
            if (profile.peak_hours.includes(h)) count *= profile.multiplier;
            count = Math.round(count * (0.7 + rng() * 0.5));
            total += count;
        }
        const vehicle_dist = {};
        let rem = total;
        VEHICLE_TYPES.forEach((vt, i) => {
            const cnt = (i === VEHICLE_TYPES.length - 1) ? rem : Math.round(total * profile.vehicle_bias[i] * (0.9 + rng() * 0.2));
            vehicle_dist[vt] = Math.min(cnt, rem);
            rem -= vehicle_dist[vt];
        });
        const avg_conf = 0.42 + rng() * 0.28;
        const hourly_now = Math.round(profile.base * (profile.peak_hours.includes(currentHour) ? profile.multiplier : 1) * (0.7 + rng() * 0.6));
        return { ...cam, total, vehicle_dist, avg_conf, hourly_now };
    }).sort((a, b) => b.total - a.total);
}

function generateDailyData() {
    const data = [];
    const today = new Date();
    for (let d = 29; d >= 0; d--) {
        const date = new Date(today);
        date.setDate(today.getDate() - d);
        const weekday = date.getDay();
        const isWeekend = weekday === 0 || weekday === 6;
        let total = Object.values(CAMERA_PROFILES).reduce((s, p) => s + p.base * 16, 0);
        total = Math.round(total * (isWeekend ? 0.65 : 1) * (0.8 + rng() * 0.4));
        data.push({ date: date.toISOString().split('T')[0], total });
    }
    return data;
}

function generatePeakHours() {
    const peaks = [];
    for (let h = 0; h < 24; h++) {
        let total = 0;
        for (const profile of Object.values(CAMERA_PROFILES)) {
            let count = profile.base;
            if (profile.peak_hours.includes(h)) count *= profile.multiplier;
            total += Math.round(count * (0.7 + rng() * 0.6));
        }
        peaks.push({ hour: h, total });
    }
    return peaks;
}

function generateRecentEvents(n = 30) {
    const events = [];
    const now = new Date();
    for (let i = 0; i < n; i++) {
        const cam = CAMERAS[Math.floor(rng() * CAMERAS.length)];
        const profile = CAMERA_PROFILES[cam.id];
        const secondsAgo = Math.floor(rng() * 300);
        const ts = new Date(now - secondsAgo * 1000);
        const vtype = pickVehicle(profile.vehicle_bias);
        const conf = (0.15 + rng() * 0.75).toFixed(4);
        events.push({ camera_id: cam.id, location: cam.location, timestamp: ts, vehicle_type: vtype, confidence_score: parseFloat(conf) });
    }
    return events.sort((a, b) => b.timestamp - a.timestamp);
}

function generateConfidenceTimeSeries() {
    const now = new Date();
    const points = [];
    for (let i = 23; i >= 0; i--) {
        const h = new Date(now - i * 60 * 60 * 1000);
        const avg = (0.38 + rng() * 0.22).toFixed(4);
        const p95 = Math.min(1, parseFloat(avg) + 0.2 + rng() * 0.1).toFixed(4);
        points.push({ label: `${String(h.getHours()).padStart(2, '0')}:00`, avg: parseFloat(avg), p95: parseFloat(p95) });
    }
    return points;
}

