function polyToSVG(points, imgW, imgH, svgW, svgH, color, fillColor) {
    const sx = svgW / imgW, sy = svgH / imgH;
    const pts = points.map(([x, y]) => `${x * sx},${y * sy}`).join(' ');
    return `<polygon points="${pts}" fill="${fillColor}" stroke="${color}" stroke-width="1.5" stroke-dasharray="4,2"/>`;
}

function renderCCTV(cameraStats) {
    const grid = document.getElementById('cctvGrid');
    grid.innerHTML = '';

    CAMERAS.forEach(cam => {
        const stat = cameraStats.find(s => s.id === cam.id) || { total: 0, hourly_now: 0, avg_conf: 0 };
        const isAlert = stat.hourly_now > 20;
        const imgSrc = "http://localhost:5001/video_feed/" + cam.id;
        const now = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';

        const card = document.createElement('div');
        card.className = 'cctv-card';
        card.innerHTML = `
      <div class="cctv-header">
        <span class="cctv-id">${cam.id.replace('CCTV_', '')}</span>
        <span class="cctv-loc">${cam.location}</span>
        <span class="cctv-badge ${isAlert ? 'alert' : ''}">${isAlert ? '⚠ ALERT' : '● ONLINE'}</span>
      </div>
      <div class="cctv-feed">
        ${imgSrc ? `<img src="${imgSrc}" alt="${cam.id}" loading="lazy">` : '<div style="background:#0a0f1e;width:100%;height:100%;display:flex;align-items:center;justify-content:center;color:#4a7399;font-family:monospace;font-size:11px">NO SIGNAL</div>'}
        
        <div class="cctv-hud">
          <span class="hud-ts">🕐 ${now}</span>
          <span class="hud-count">${isAlert ? '⚠' : ''} ${stat.hourly_now} DETEKSI/JAM</span>
        </div>
      </div>
      <div class="cctv-stats">
        <div class="stat-mini">
          <div class="stat-mini-val" style="color:var(--red)">${stat.total.toLocaleString()}</div>
          <div class="stat-mini-lbl">Total Hari Ini</div>
        </div>
        <div class="stat-mini">
          <div class="stat-mini-val" style="color:var(--amber)">${stat.hourly_now}</div>
          <div class="stat-mini-lbl">Jam Ini</div>
        </div>
        <div class="stat-mini">
          <div class="stat-mini-val" style="color:var(--cyan)">${stat.avg_conf.toFixed(2)}</div>
          <div class="stat-mini-lbl">Avg Conf</div>
        </div>
      </div>
    `;
        grid.appendChild(card);
    });
}

