function renderFeed(events) {
    const body = document.getElementById('feedBody');
    body.innerHTML = '';
    document.getElementById('feedCount').textContent = `${events.length} EVENT TERAKHIR`;

    events.slice(0, 20).forEach(ev => {
        const row = document.createElement('div');
        row.className = 'feed-row';
        const ts = ev.timestamp;
        const timeStr = `${String(ts.getHours()).padStart(2, '0')}:${String(ts.getMinutes()).padStart(2, '0')}:${String(ts.getSeconds()).padStart(2, '0')}`;
        const confPct = Math.round(ev.confidence_score * 100);
        row.innerHTML = `
      <span class="feed-time">${timeStr}</span>
      <span class="feed-cam">${ev.camera_id.replace('CCTV_', '')}</span>
      <div class="feed-vtype">
        <span class="vtype-icon">${VEHICLE_ICONS[ev.vehicle_type]}</span>
        <span class="vtype-label">${ev.vehicle_type}</span>
      </div>
      <div>
        <div class="conf-val">${confPct}%</div>
        <div class="conf-bar"><div class="conf-fill" style="width:${confPct}%"></div></div>
      </div>
    `;
        body.appendChild(row);
    });
}

function renderHotspot(cameraStats) {
    const body = document.getElementById('hotspotBody');
    const maxTotal = cameraStats[0]?.total || 1;
    body.innerHTML = cameraStats.map((cam, i) => {
        const topVehicle = Object.entries(cam.vehicle_dist).sort((a, b) => b[1] - a[1])[0];
        const rank = i + 1;
        const rankClass = rank <= 3 ? `rank-${rank}` : 'rank-n';
        const barPct = Math.round((cam.total / maxTotal) * 100);
        const statusColor = rank === 1 ? 'var(--red)' : rank <= 2 ? 'var(--amber)' : 'var(--cyan)';
        const statusTxt = rank === 1 ? '🔴 KRITIS' : rank <= 2 ? '🟡 TINGGI' : '🟢 NORMAL';
        return `<tr>
      <td><span class="rank-badge ${rankClass}">${rank}</span></td>
      <td class="camera-id-cell">${cam.id}</td>
      <td style="color:var(--text-2)">${cam.location}</td>
      <td style="color:var(--text-1);font-weight:700">${cam.total.toLocaleString()}</td>
      <td class="bar-cell">
        <div class="mini-bar"><div class="mini-fill" style="width:${barPct}%"></div></div>
        <span style="font-size:9px;color:var(--text-3)">${barPct}%</span>
      </td>
      <td style="color:var(--text-2)">${VEHICLE_ICONS[topVehicle[0]]} ${topVehicle[0]} (${topVehicle[1].toLocaleString()})</td>
      <td style="color:var(--cyan)">${(cam.avg_conf * 100).toFixed(1)}%</td>
      <td style="color:${statusColor}">${statusTxt}</td>
    </tr>`;
    }).join('');
}

// ============================================================
// CLOCK
// ============================================================
function updateClock() {
    const now = new Date();
    const wib = new Date(now.getTime() + (7 * 60 * 60 * 1000));
    const t = wib.toISOString().replace('T', ' ').slice(11, 19);
    document.getElementById('clockEl').textContent = t;
}
setInterval(updateClock, 1000);
updateClock();

